@* Displays a single task with title, assignee, priority badge, due date, and move buttons *@

<div class="card mb-2">
    <div class="card-body p-2">
        <div class="d-flex justify-content-between align-items-start mb-1">
            <h6 class="card-title mb-0">@Task.Title</h6>
            <span class="badge @PriorityClass">@Task.Priority</span>
        </div>
        <p class="card-text text-muted small mb-1">@Task.Assignee</p>
        <p class="card-text text-muted small mb-2">@Task.DueDate.ToString("MMM dd")</p>
        <div class="d-flex gap-1">
            @if (CanMoveLeft)
            {
                <button class="btn btn-outline-secondary btn-sm" @onclick="() => OnMoveLeft.InvokeAsync(Task.Id)" disabled="@IsMoving">
                    &larr; Move Left
                </button>
            }
            @if (CanMoveRight)
            {
                <button class="btn btn-outline-secondary btn-sm" @onclick="() => OnMoveRight.InvokeAsync(Task.Id)" disabled="@IsMoving">
                    Move Right &rarr;
                </button>
            }
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public TaskItem Task { get; set; } = default!;
    [Parameter] public bool CanMoveLeft { get; set; }
    [Parameter] public bool CanMoveRight { get; set; }
    [Parameter] public EventCallback<int> OnMoveLeft { get; set; }
    [Parameter] public EventCallback<int> OnMoveRight { get; set; }
    [Parameter] public bool IsMoving { get; set; }

    private string PriorityClass => Task.Priority switch
    {
        "High" => "bg-danger",
        "Medium" => "bg-warning text-dark",
        "Low" => "bg-success",
        _ => "bg-secondary"
    };
}

@* Inline form for creating a new task within a column *@

@if (!IsVisible)
{
    <button class="btn btn-outline-primary btn-sm w-100" @onclick="Show">+ Add Task</button>
}
else
{
    <div class="card border-primary">
        <div class="card-body p-2">
            <div class="mb-2">
                <input type="text" class="form-control form-control-sm" placeholder="Title" @bind="Title" />
            </div>
            <div class="mb-2">
                <input type="text" class="form-control form-control-sm" placeholder="Assignee" @bind="Assignee" />
            </div>
            <div class="mb-2">
                <select class="form-select form-select-sm" @bind="Priority">
                    <option value="High">High</option>
                    <option value="Medium">Medium</option>
                    <option value="Low">Low</option>
                </select>
            </div>
            <div class="mb-2">
                <input type="date" class="form-control form-control-sm" @bind="DueDate" />
            </div>
            <div class="d-flex gap-1">
                <button class="btn btn-primary btn-sm" @onclick="Save" disabled="@IsSaving">
                    @(IsSaving ? "Saving..." : "Save")
                </button>
                <button class="btn btn-secondary btn-sm" @onclick="Cancel" disabled="@IsSaving">Cancel</button>
            </div>
            @if (!string.IsNullOrEmpty(ErrorMessage))
            {
                <div class="text-danger small mt-1">@ErrorMessage</div>
            }
        </div>
    </div>
}

@code {
    [Parameter, EditorRequired] public string DefaultStatus { get; set; } = "";
    [Parameter] public EventCallback<TaskItem> OnTaskCreated { get; set; }

    private bool IsVisible;
    private bool IsSaving;
    private string Title = "";
    private string Assignee = "";
    private string Priority = "Medium";
    private DateTime DueDate = DateTime.Today.AddDays(7);
    private string? ErrorMessage;

    private void Show() => IsVisible = true;

    private void Cancel()
    {
        ResetForm();
        IsVisible = false;
    }

    private async Task Save()
    {
        ErrorMessage = null;
        if (string.IsNullOrWhiteSpace(Title))
        {
            ErrorMessage = "Title is required.";
            return;
        }

        IsSaving = true;
        try
        {
            await OnTaskCreated.InvokeAsync(null!); // Signal parent with form data via callback
        }
        finally
        {
            IsSaving = false;
        }
    }

    // Expose form values so the parent can read them before calling the service
    public (string Title, string Assignee, string Priority, DateTime DueDate) GetFormData()
        => (Title, Assignee, Priority, DueDate);

    public void ResetAndHide()
    {
        ResetForm();
        IsVisible = false;
        StateHasChanged();
    }

    public void ShowError(string message)
    {
        ErrorMessage = message;
        IsSaving = false;
        StateHasChanged();
    }

    private void ResetForm()
    {
        Title = "";
        Assignee = "";
        Priority = "Medium";
        DueDate = DateTime.Today.AddDays(7);
        ErrorMessage = null;
    }
}

@* Displays aggregate stats: total tasks, per-column counts, and overdue count *@

<div class="d-flex flex-wrap gap-3 mb-3 p-3 bg-light rounded">
    <div>
        <strong>Total:</strong> @Total
    </div>
    <div>
        <strong>To Do:</strong> @TodoCount
    </div>
    <div>
        <strong>In Progress:</strong> @InProgressCount
    </div>
    <div>
        <strong>Done:</strong> @DoneCount
    </div>
    <div class="@(OverdueCount > 0 ? "text-danger" : "")">
        <strong>Overdue:</strong> @OverdueCount
    </div>
</div>

@code {
    [Parameter] public int Total { get; set; }
    [Parameter] public int TodoCount { get; set; }
    [Parameter] public int InProgressCount { get; set; }
    [Parameter] public int DoneCount { get; set; }
    [Parameter] public int OverdueCount { get; set; }
}

@* Search input that filters tasks by title *@

<div class="mb-3">
    <input type="text"
           class="form-control"
           placeholder="Search tasks by title..."
           value="@SearchTerm"
           @oninput="OnInput" />
</div>

@code {
    [Parameter] public string SearchTerm { get; set; } = "";
    [Parameter] public EventCallback<string> SearchTermChanged { get; set; }

    private async Task OnInput(ChangeEventArgs e)
    {
        var value = e.Value?.ToString() ?? "";
        await SearchTermChanged.InvokeAsync(value);
    }
}

@* A single Kanban column: header with count, task cards, and add-task form *@

<div class="col">
    <div class="card h-100">
        <div class="card-header d-flex justify-content-between align-items-center">
            <h5 class="mb-0">@ColumnName</h5>
            <span class="badge bg-secondary">@Tasks.Count</span>
        </div>
        <div class="card-body d-flex flex-column gap-2 overflow-auto" style="max-height: 70vh;">
            @foreach (var task in Tasks)
            {
                <TaskCard Task="task"
                          CanMoveLeft="CanMoveLeft"
                          CanMoveRight="CanMoveRight"
                          OnMoveLeft="OnMoveLeft"
                          OnMoveRight="OnMoveRight"
                          IsMoving="MovingTaskId == task.Id" />
            }
            <AddTaskForm @ref="addTaskFormRef"
                         DefaultStatus="@ColumnName"
                         OnTaskCreated="HandleTaskCreated" />
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public string ColumnName { get; set; } = "";
    [Parameter] public List<TaskItem> Tasks { get; set; } = new();
    [Parameter] public bool CanMoveLeft { get; set; }
    [Parameter] public bool CanMoveRight { get; set; }
    [Parameter] public EventCallback<int> OnMoveLeft { get; set; }
    [Parameter] public EventCallback<int> OnMoveRight { get; set; }
    [Parameter] public int? MovingTaskId { get; set; }
    [Parameter] public EventCallback<(string Title, string Assignee, string Priority, DateTime DueDate, string Status)> OnAddTask { get; set; }

    private AddTaskForm? addTaskFormRef;

    private async Task HandleTaskCreated()
    {
        if (addTaskFormRef is null) return;

        var (title, assignee, priority, dueDate) = addTaskFormRef.GetFormData();
        if (string.IsNullOrWhiteSpace(title))
        {
            addTaskFormRef.ShowError("Title is required.");
            return;
        }

        try
        {
            await OnAddTask.InvokeAsync((title, assignee, priority, dueDate, ColumnName));
            addTaskFormRef.ResetAndHide();
        }
        catch (Exception ex)
        {
            addTaskFormRef.ShowError($"Failed to add task: {ex.Message}");
        }
    }
}

@page "/board"
@using sv_fcd34d7121224a39bd25b0bc0d1b3e47.Components.Board
@inject ITaskService TaskService
@rendermode InteractiveServer

<PageTitle>Kanban Board</PageTitle>

<h3 class="mb-3">Kanban Board</h3>

@if (isLoading)
{
    <div class="d-flex justify-content-center p-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error:</strong> @errorMessage
        <button class="btn btn-outline-danger btn-sm ms-2" @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardSummaryBar Total="allTasks.Count"
                     TodoCount="todoTasks.Count"
                     InProgressCount="inProgressTasks.Count"
                     DoneCount="doneTasks.Count"
                     OverdueCount="overdueTasks.Count" />

    <BoardSearchBar @bind-SearchTerm="searchTerm" SearchTermChanged="OnSearchChanged" />

    <div class="row g-3">
        <KanbanColumn ColumnName="To Do"
                      Tasks="filteredTodo"
                      CanMoveLeft="false"
                      CanMoveRight="true"
                      OnMoveRight="id => MoveTask(id, \"In Progress\")"
                      OnAddTask="HandleAddTask"
                      MovingTaskId="movingTaskId" />

        <KanbanColumn ColumnName="In Progress"
                      Tasks="filteredInProgress"
                      CanMoveLeft="true"
                      CanMoveRight="true"
                      OnMoveLeft="id => MoveTask(id, \"To Do\")"
                      OnMoveRight="id => MoveTask(id, \"Done\")"
                      OnAddTask="HandleAddTask"
                      MovingTaskId="movingTaskId" />

        <KanbanColumn ColumnName="Done"
                      Tasks="filteredDone"
                      CanMoveLeft="true"
                      CanMoveRight="false"
                      OnMoveLeft="id => MoveTask(id, \"In Progress\")"
                      OnAddTask="HandleAddTask"
                      MovingTaskId="movingTaskId" />
    </div>
}

@code {
    private List<TaskItem> allTasks = new();
    private string searchTerm = "";
    private bool isLoading = true;
    private string? errorMessage;
    private int? movingTaskId;

    // Unfiltered column lists (used for stats)
    private List<TaskItem> todoTasks => allTasks.Where(t => t.Status == "To Do").ToList();
    private List<TaskItem> inProgressTasks => allTasks.Where(t => t.Status == "In Progress").ToList();
    private List<TaskItem> doneTasks => allTasks.Where(t => t.Status == "Done").ToList();
    private List<TaskItem> overdueTasks => allTasks.Where(t => t.DueDate.Date < DateTime.Today && t.Status != "Done").ToList();

    // Filtered column lists (used for display)
    private List<TaskItem> filteredTodo => ApplySearch(todoTasks);
    private List<TaskItem> filteredInProgress => ApplySearch(inProgressTasks);
    private List<TaskItem> filteredDone => ApplySearch(doneTasks);

    private List<TaskItem> ApplySearch(List<TaskItem> tasks)
    {
        if (string.IsNullOrWhiteSpace(searchTerm))
            return tasks;
        return tasks.Where(t => t.Title.Contains(searchTerm, StringComparison.OrdinalIgnoreCase)).ToList();
    }

    protected override async Task OnInitializedAsync()
    {
        await LoadTasks();
    }

    private async Task LoadTasks()
    {
        isLoading = true;
        errorMessage = null;

        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isLoading = false;
        }
    }

    private async Task MoveTask(int taskId, string newStatus)
    {
        movingTaskId = taskId;
        try
        {
            await TaskService.UpdateTaskStatusAsync(taskId, newStatus);
            var task = allTasks.First(t => t.Id == taskId);
            var index = allTasks.IndexOf(task);
            allTasks[index] = task with { Status = newStatus };
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to move task: {ex.Message}";
        }
        finally
        {
            movingTaskId = null;
        }
    }

    private async Task HandleAddTask((string Title, string Assignee, string Priority, DateTime DueDate, string Status) data)
    {
        var newTask = await TaskService.CreateTaskAsync(data.Title, data.Assignee, data.Priority, data.DueDate);
        // The service creates tasks; if it doesn't set the status to the column's status, update it
        if (newTask.Status != data.Status)
        {
            await TaskService.UpdateTaskStatusAsync(newTask.Id, data.Status);
            newTask = newTask with { Status = data.Status };
        }
        allTasks.Add(newTask);
    }

    private void OnSearchChanged(string value)
    {
        searchTerm = value;
    }
}

