@code {
    private List<TaskItem> allTasks = new();
    private string searchTerm = "";
    private bool isLoading = true;
    private string? errorMessage;
    private int? movingTaskId;

    // Unfiltered column lists (used for stats)
    private List<TaskItem> todoTasks => allTasks.Where(t => t.Status == "To Do").ToList();
    private List<TaskItem> inProgressTasks => allTasks.Where(t => t.Status == "In Progress").ToList();
    private List<TaskItem> doneTasks => allTasks.Where(t => t.Status == "Done").ToList();
    private List<TaskItem> overdueTasks => allTasks.Where(t => t.DueDate.Date < DateTime.Today && t.Status != "Done").ToList();

    // Filtered column lists (used for display)
    private List<TaskItem> filteredTodo => ApplySearch(todoTasks);
    private List<TaskItem> filteredInProgress => ApplySearch(inProgressTasks);
    private List<TaskItem> filteredDone => ApplySearch(doneTasks);

