+        <div class="d-flex justify-content-between align-items-start mb-1">
+            <h6 class="card-title mb-0">@Task.Title</h6>
+            <span class="badge @PriorityClass">@Task.Priority</span>
+        </div>
+        <p class="card-text text-muted small mb-1">@Task.Assignee</p>
+        <p class="card-text text-muted small mb-2">@Task.DueDate.ToString("MMM dd")</p>
+        <div class="d-flex gap-1">
+            @if (CanMoveLeft)
+            {
+                <button class="btn btn-outline-secondary btn-sm" @onclick="() => OnMoveLeft.InvokeAsync(Task.Id)" disabled="@IsMoving">
+                    &larr; Move Left
+                </button>
+            }
+            @if (CanMoveRight)
+            {
+                <button class="btn btn-outline-secondary btn-sm" @onclick="() => OnMoveRight.InvokeAsync(Task.Id)" disabled="@IsMoving">
+                    Move Right &rarr;
+                </button>
+            }
+        </div>
+    </div>
+</div>
+
+@code {
+    [Parameter, EditorRequired] public TaskItem Task { get; set; } = default!;
+    [Parameter] public bool CanMoveLeft { get; set; }
+    [Parameter] public bool CanMoveRight { get; set; }
+    [Parameter] public EventCallback<int> OnMoveLeft { get; set; }
