@* Inline form for creating a new task within a column *@

@if (!IsVisible)
{
    <button class="btn btn-outline-primary btn-sm w-100" @onclick="Show">+ Add Task</button>
}
else
{
    <div class="card border-primary">
        <div class="card-body p-2">
            <div class="mb-2">
                <input type="text" class="form-control form-control-sm" placeholder="Title" @bind="Title" />
            </div>
            <div class="mb-2">
                <input type="text" class="form-control form-control-sm" placeholder="Assignee" @bind="Assignee" />
            </div>
            <div class="mb-2">
                <select class="form-select form-select-sm" @bind="Priority">
                    <option value="High">High</option>
                    <option value="Medium">Medium</option>
                    <option value="Low">Low</option>
                </select>
            </div>
            <div class="mb-2">
                <input type="date" class="form-control form-control-sm" @bind="DueDate" />
            </div>
            <div class="d-flex gap-1">
                <button class="btn btn-primary btn-sm" @onclick="Save" disabled="@IsSaving">
                    @(IsSaving ? "Saving..." : "Save")
                </button>
                <button class="btn btn-secondary btn-sm" @onclick="Cancel" disabled="@IsSaving">Cancel</button>
            </div>
            @if (!string.IsNullOrEmpty(ErrorMessage))
            {
                <div class="text-danger small mt-1">@ErrorMessage</div>
            }
        </div>
    </div>
}

@code {
    [Parameter, EditorRequired] public string DefaultStatus { get; set; } = "";
    [Parameter] public EventCallback<TaskItem> OnTaskCreated { get; set; }

    private bool IsVisible;
    private bool IsSaving;
    private string Title = "";
    private string Assignee = "";
    private string Priority = "Medium";
    private DateTime DueDate = DateTime.Today.AddDays(7);
    private string? ErrorMessage;

    private void Show() => IsVisible = true;

    private void Cancel()
    {
        ResetForm();
        IsVisible = false;
    }

    private async Task Save()
    {
        ErrorMessage = null;
        if (string.IsNullOrWhiteSpace(Title))
        {
            ErrorMessage = "Title is required.";
            return;
        }

        IsSaving = true;
        try
        {
            await OnTaskCreated.InvokeAsync(null!); // Signal parent with form data via callback
        }
        finally
        {
            IsSaving = false;
        }
    }

    // Expose form values so the parent can read them before calling the service
    public (string Title, string Assignee, string Priority, DateTime DueDate) GetFormData()
        => (Title, Assignee, Priority, DueDate);

    public void ResetAndHide()
    {
        ResetForm();
        IsVisible = false;
        StateHasChanged();
    }

    public void ShowError(string message)
    {
        ErrorMessage = message;
        IsSaving = false;
        StateHasChanged();
    }

    private void ResetForm()
    {
        Title = "";
        Assignee = "";
        Priority = "Medium";
        DueDate = DateTime.Today.AddDays(7);
        ErrorMessage = null;
    }
}

