@* Displays aggregate stats: total tasks, per-column counts, and overdue count *@

<div class="d-flex flex-wrap gap-3 mb-3 p-3 bg-light rounded">
    <div>
        <strong>Total:</strong> @Total
    </div>
    <div>
        <strong>To Do:</strong> @TodoCount
    </div>
    <div>
        <strong>In Progress:</strong> @InProgressCount
    </div>
    <div>
        <strong>Done:</strong> @DoneCount
    </div>
    <div class="@(OverdueCount > 0 ? "text-danger" : "")">
        <strong>Overdue:</strong> @OverdueCount
    </div>
</div>

@code {
    [Parameter] public int Total { get; set; }
    [Parameter] public int TodoCount { get; set; }
    [Parameter] public int InProgressCount { get; set; }
    [Parameter] public int DoneCount { get; set; }
    [Parameter] public int OverdueCount { get; set; }
}

@* Search input that filters tasks by title *@

<div class="mb-3">
    <input type="text"
           class="form-control"
           placeholder="Search tasks by title..."
           value="@SearchTerm"
           @oninput="OnInput" />
</div>

@code {
    [Parameter] public string SearchTerm { get; set; } = "";
    [Parameter] public EventCallback<string> SearchTermChanged { get; set; }

    private async Task OnInput(ChangeEventArgs e)
    {
        var value = e.Value?.ToString() ?? "";
        await SearchTermChanged.InvokeAsync(value);
    }
}

@* A single Kanban column: header with count, task cards, and add-task form *@

<div class="col">
    <div class="card h-100">
        <div class="card-header d-flex justify-content-between align-items-center">
            <h5 class="mb-0">@ColumnName</h5>
            <span class="badge bg-secondary">@Tasks.Count</span>
        </div>
        <div class="card-body d-flex flex-column gap-2 overflow-auto" style="max-height: 70vh;">
            @foreach (var task in Tasks)
            {
                <TaskCard Task="task"
                          CanMoveLeft="CanMoveLeft"
                          CanMoveRight="CanMoveRight"
                          OnMoveLeft="OnMoveLeft"
                          OnMoveRight="OnMoveRight"
                          IsMoving="MovingTaskId == task.Id" />
            }
            <AddTaskForm @ref="addTaskFormRef"
                         DefaultStatus="@ColumnName"
                         OnTaskCreated="HandleTaskCreated" />
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public string ColumnName { get; set; } = "";
    [Parameter] public List<TaskItem> Tasks { get; set; } = new();
    [Parameter] public bool CanMoveLeft { get; set; }
    [Parameter] public bool CanMoveRight { get; set; }
    [Parameter] public EventCallback<int> OnMoveLeft { get; set; }
    [Parameter] public EventCallback<int> OnMoveRight { get; set; }
    [Parameter] public int? MovingTaskId { get; set; }
    [Parameter] public EventCallback<(string Title, string Assignee, string Priority, DateTime DueDate, string Status)> OnAddTask { get; set; }

    private AddTaskForm? addTaskFormRef;

    private async Task HandleTaskCreated()
    {
        if (addTaskFormRef is null) return;

        var (title, assignee, priority, dueDate) = addTaskFormRef.GetFormData();
        if (string.IsNullOrWhiteSpace(title))
        {
            addTaskFormRef.ShowError("Title is required.");
            return;
        }

        try
        {
            await OnAddTask.InvokeAsync((title, assignee, priority, dueDate, ColumnName));
            addTaskFormRef.ResetAndHide();
        }
        catch (Exception ex)
        {
            addTaskFormRef.ShowError($"Failed to add task: {ex.Message}");
        }
    }
}

